package com.panini.back.entity;
import jakarta.persistence.*;
@Entity @Table(name="stickers") public class Sticker { @Id @GeneratedValue(strategy=GenerationType.IDENTITY) private Long id; @Column(nullable=false, unique=true) private String code; @Column(nullable=false) private String name; @Column(nullable=false) private String type; @Column(nullable=false) private String countryCode; @Column(nullable=false) private String categoryCode; private Integer pageNumber; private Boolean specialSticker=false; public Long getId(){return id;} public void setId(Long id){this.id=id;} public String getCode(){return code;} public void setCode(String code){this.code=code;} public String getName(){return name;} public void setName(String name){this.name=name;} public String getType(){return type;} public void setType(String type){this.type=type;} public String getCountryCode(){return countryCode;} public void setCountryCode(String countryCode){this.countryCode=countryCode;} public String getCategoryCode(){return categoryCode;} public void setCategoryCode(String categoryCode){this.categoryCode=categoryCode;} public Integer getPageNumber(){return pageNumber;} public void setPageNumber(Integer pageNumber){this.pageNumber=pageNumber;} public Boolean getSpecialSticker(){return specialSticker;} public void setSpecialSticker(Boolean specialSticker){this.specialSticker=specialSticker;} }
